Rule.Source:
import sailpoint.api.*;
import sailpoint.connector.*;
import sailpoint.object.*;
import sailpoint.tools.xml.AbstractXmlObject;

try
{
	var connector = "IIQ".equals(application) ? null : ConnectorFactory.getConnector(context.getObject(Application.class, application), null);
	if ((connector == null) && !"Provision".equals(operation))
	{
		throw new RuntimeException("No such connector");
	}
	switch (operation)
	{
		case "Test":
			connector.testConfiguration();
			rulerunnerOutput.addMessage("Test successful");
			break;
		case "Iterate":
			var count = 0;
			rulerunnerOutput.startTimeMonitoring();
			rulerunnerOutput.printNoEscape("<pre>");
			try
			{
				var resultSet = connector.iterateObjects(objectType, null, null);
				while (resultSet.hasNext())
				{
					if ((maxObjects != null) && (count >= maxObjects))
					{
						rulerunnerOutput.addMessage("Maximum object count was reached");
						break;
					}
					if (rulerunnerOutput.isTerminationRequested(count == 0))
					{
						break;
					}
					rulerunnerOutput.print(resultSet.next().toXml(false));
					++count;
				}
			}
			finally
			{
				rulerunnerOutput.printNoEscape("</pre>");
			}
			rulerunnerOutput.addMessage("%d objects iterated in %.02f seconds", count, rulerunnerOutput.getDuration());
			break;
		case "Read":
			var account = connector.getObject(objectType, nativeIdentity, null);
			rulerunnerOutput.printNoEscape("<pre>");
			rulerunnerOutput.print((account != null) ? account.toXml(false) : "null");
			rulerunnerOutput.printNoEscape("</pre>");
			break;
		case "Provision":
			var provisioningPlan = new ProvisioningPlan();
			provisioningPlan.setSource("six_direct_connector_access");
			var objectRequest;
			if ("account".equals(objectType))
			{
				objectRequest = new ProvisioningPlan.AccountRequest(
					ProvisioningPlan.AccountRequest.Operation.valueOf(provisioningOperation),
					application,
					null,
					(useProvisioner && "Create".equals(provisioningOperation)) ? null : nativeIdentity
				);
			}
			else
			{
				objectRequest = new ProvisioningPlan.ObjectRequest();
				objectRequest.setOp(ProvisioningPlan.ObjectOperation.valueOf(provisioningOperation));
				objectRequest.setApplication(application);
				objectRequest.setType(objectType);
				objectRequest.setNativeIdentity(nativeIdentity);
			}
			objectRequest.setTargetIntegration(application);
			if (("Create".equals(provisioningOperation) || "Modify".equals(provisioningOperation)) && (attributeOperation != null) && !attributeOperation.isEmpty())
			{
				var attributeRequest = new ProvisioningPlan.AttributeRequest(
						attributeName,
						ProvisioningPlan.Operation.valueOf(attributeOperation),
						attributeValue
				);
				objectRequest.add(attributeRequest);
			}
			provisioningPlan.add(objectRequest);
			var provisioningResult = null;
			if ((connector == null) || useProvisioner)
			{
				if ("account".equals(objectType))
				{
					if ((connector == null) || "Create".equals(provisioningOperation))
					{
						provisioningPlan.setIdentity(context.getObject(Identity.class, nativeIdentity));
					}
					else
					{
						var account = context.getUniqueObject(Link.class, Filter.and(
							Filter.eq("application.name", application),
							Filter.eq("nativeIdentity", nativeIdentity)
						));
						if (account == null)
						{
							throw new RuntimeException("No such account");
						}
						provisioningPlan.setIdentity(account.getIdentity());
					}
				}
				var provisioner = new Provisioner(context);
				var provisioningProject = provisioner.compile(provisioningPlan);
				if (verbose)
				{
					rulerunnerOutput.printNoEscape("<pre>");
					rulerunnerOutput.print(provisioningProject.toXml(false));
					rulerunnerOutput.printNoEscape("</pre>");
				}
				provisioner.execute(provisioningProject);
				provisioningResult = provisioningProject;
			}
			else
			{
				if (verbose)
				{
					rulerunnerOutput.printNoEscape("<pre>");
					rulerunnerOutput.print(provisioningPlan.toXml(false));
					rulerunnerOutput.printNoEscape("</pre>");
				}
				provisioningResult = connector.provision(provisioningPlan);
			}
			rulerunnerOutput.printNoEscape("<pre>");
			rulerunnerOutput.print(((provisioningResult != null) ? provisioningResult : provisioningPlan).toXml(false));
			rulerunnerOutput.printNoEscape("</pre>");
			break;
	}
}
catch (Exception e)
{
	rulerunnerOutput.addError(e);
}
